import { useState } from "react";
import { motion } from "framer-motion";
import SEOHead from "@/components/SEOHead";
import AdPlaceholder from "@/components/AdPlaceholder";
import RelatedTools from "@/components/RelatedTools";
import ShareButton from "@/components/ShareButton";
import FAQItem from "@/components/FAQItem";


const FAQS = [
  { q: "How do I read resistor color codes?", a: "For 4-band resistors: Band 1 = first digit, Band 2 = second digit, Band 3 = multiplier, Band 4 = tolerance. Example: Brown-Black-Red-Gold = 1, 0,  x 100 = 1,000 ohm - The value formula is: (Band1  x  10 + Band2)  x  Multiplier." },
  { q: "How do I calculate resistors in series?", a: "Resistors in series simply add: Rtotal = R1 + R2 + R3 + ... Example: 470 ohm + 330 ohm + 100 ohm = 900 ohm. Current through each resistor is the same; voltage divides proportionally. Use series to increase resistance or create voltage dividers." },
  { q: "How do I calculate resistors in parallel?", a: "For parallel resistors: 1/Rtotal = 1/R1 + 1/R2 + 1/R3 + ... For two equal resistors in parallel, the result is half each value. Example: two 100 ohm in parallel = 50 ohm. Parallel resistance is always less than the smallest individual resistor." },
  { q: "What is resistor tolerance?", a: "Tolerance indicates the maximum allowed deviation from the stated value. Gold band = - Silver = - Brown = - Red = - For a 1,000 ohm - resistor, actual resistance can be 950-1,050 ohm. For precision analog circuits, use - (or better) resistors." },
  { q: "What do the E-series (E12, E24, E96) mean?", a: "The E-series defines standard preferred resistance values. E12 has 12 values per decade (- tolerance), E24 has 24 values (- E96 has 96 values (- Higher E-numbers have finer value spacing for precision circuits. Most commercial resistors follow E24 or E96 series." },
  { q: "What is the power rating of a resistor?", a: "Power rating (in watts) indicates how much heat a resistor can safely dissipate. Common values: 1/8W, 1/4W, 1/2W, 1W, 2W, 5W. Power dissipated = I- = V- Always choose a resistor with a power rating at least 2 x  the expected dissipation for safety margin. Exceeding the rating causes overheating and failure." },
  { q: "How do I identify surface-mount (SMD) resistors?", a: "SMD resistors use a 3 or 4-digit code instead of color bands. 3-digit code: first two digits = significant digits, third = number of zeros. Example: '472' = 47  x  100 = 4,700 ohm. 4-digit code: first three digits = significant digits, fourth = zeros. Example: '4702' = 470  x  100 = 47,000 ohm (47k ohm)." },
  { q: "What resistor should I use for an LED?", a: "R = (Supply Voltage - LED Forward Voltage) / LED Current. For a 5V supply, red LED (Vf - 2.0V), 20mA: R = (5 - 2) / 0.020 = 150 ohm. Use the next standard value up (150 ohm or 180 ohm). Always limit current to extend LED life - running at 10-15mA instead of 20mA makes LEDs last 3-5 x  longer." },
];

const COLORS = ["Black","Brown","Red","Orange","Yellow","Green","Blue","Violet","Gray","White"] as const;
const MULT = [" x 1"," x 10"," x 100"," x 1K"," x 10K"," x 100K"," x 1M"," x 10M"," x 0.1"," x 0.01"] as const;
const TOL = ["1", "2", "0.5", "0.25", "0.1", "0.05", "5", "10"] as const;
const multValues = [1,10,100,1000,10000,100000,1000000,10000000,0.1,0.01];
const tolColors = ["Brown","Red","Green","Blue","Violet","Gray","Gold","Silver"];
const COLOR_HEX: Record<string, string> = {Black:"#1a1a1a",Brown:"#8B4513",Red:"#DC143C",Orange:"#FF8C00",Yellow:"#FFD700",Green:"#228B22",Blue:"#4169E1",Violet:"#8B008B",Gray:"#808080",White:"#F5F5F5"};

const COLOR_TABLE = [
  ["Black", "0", " x 1", "-"],
  ["Brown", "1", " x 10", "1%"],
  ["Red", "2", " x 100", "2%"],
  ["Orange", "3", " x 1K", "-"],
  ["Yellow", "4", " x 10K", "-"],
  ["Green", "5", " x 100K", "0.5%"],
  ["Blue", "6", " x 1M", "-"],
  ["Violet", "7", " x 10M", "0.1%"],
  ["Gray", "8", " x 0.1", "-"],
  ["White", "9", " x 0.01", "-"],
  ["Gold", "-", " x 0.1", "5%"],
  ["Silver", "-", " x 0.01", "10%"],
];

export default function ResistorCalculator() {
  const [b1, setB1] = useState(1);
  const [b2, setB2] = useState(0);
  const [b3, setB3] = useState(2);
  const [b4, setB4] = useState(6);

  const resistance = (b1 * 10 + b2) * multValues[b3];
  const tolerance = TOL[b4 < TOL.length ? b4 : 6];

  function fmtR(r: number) {
    if (r >= 1e6) return `${(r/1e6).toFixed(2)} M ohm`;
    if (r >= 1e3) return `${(r/1e3).toFixed(2)} k ohm`;
    return `${r.toFixed(2)}  ohm`;
  }

  const minR = resistance * (1 - parseFloat(tolerance) / 100);
  const maxR = resistance * (1 + parseFloat(tolerance) / 100);

  return (
    <>
      <SEOHead
        title="Free Resistor Color Code Calculator Online - Decode Resistor Values Instantly | CalcHive"
        description="Free online resistor color code calculator. Decode 4-band resistor color codes to find resistance value and tolerance instantly. 100% free for electronics students and engineers, no signup required."
        canonical="/resistor-calculator"
        keywords="free resistor color code calculator, resistor calculator online free, 4 band resistor color code calculator free, decode resistor value free, electronics resistor calculator free"
        category="Electrical Calculators"
        faqs={FAQS}
      />
      <main className="max-w-3xl mx-auto px-4 sm:px-6 py-10">
        <div className="mb-8">
          <span className="text-xs font-semibold uppercase tracking-widest text-yellow-600 dark:text-yellow-400 bg-yellow-50 dark:bg-yellow-950/50 px-3 py-1 rounded-full mb-4 inline-block">Electronics</span>
          <h1 className="text-3xl sm:text-4xl font-extrabold text-foreground tracking-tight mb-3">Free Resistor Color Code Calculator Online</h1>
          <p className="text-muted-foreground leading-relaxed">Use this free resistor color code calculator to decode resistor value free from 4-band color codes. This resistor calculator online free also works as a 4 band resistor color code calculator free and electronics resistor calculator free.</p>
        </div>
        <AdPlaceholder size="banner" className="mb-8" />
        <section className="bg-card border border-border rounded-2xl p-6 sm:p-8 shadow-md mb-8">
          <div className="flex justify-center gap-1 sm:gap-2 mb-8 h-20 items-center">
            <div className="flex-1 h-4 bg-[#C4A882] rounded-l-full" />
            {[b1, b2, b3, b4].map((band, idx) => {
              const color = idx < 3 ? COLORS[band] : tolColors[band];
              return <div key={idx} style={{ backgroundColor: COLOR_HEX[color] || "#ccc" }} className="w-8 h-16 rounded-sm shadow-inner border border-black/10" />;
            })}
            <div className="flex-1 h-4 bg-[#C4A882] rounded-r-full" />
          </div>
          <div className="grid grid-cols-2 sm:grid-cols-4 gap-4 mb-8">
            {[
              { label: "Band 1 (1st digit)", val: b1, set: setB1, opts: COLORS.map((c,i) => ({ c, i })) },
              { label: "Band 2 (2nd digit)", val: b2, set: setB2, opts: COLORS.map((c,i) => ({ c, i })) },
              { label: "Band 3 (Multiplier)", val: b3, set: setB3, opts: MULT.map((m,i) => ({ c: COLORS[i] || "Gray", i, label: m })) },
              { label: "Band 4 (Tolerance)", val: b4, set: setB4, opts: tolColors.map((c,i) => ({ c, i, label: TOL[i] })) },
            ].map(({ label, val, set, opts }) => (
              <div key={label}>
                <label className="text-xs font-semibold text-muted-foreground mb-2 block">{label}</label>
                <select value={val} onChange={e => set(Number(e.target.value))} className="w-full px-2 py-2 rounded-xl border border-border bg-background text-foreground focus:outline-none focus:ring-2 focus:ring-primary/40 text-xs">
                  {(opts as Array<{ c: string; i: number; label?: string }>).map(({ c, i, label: l }) => <option key={i} value={i}>{c}{l ? ` (${l})` : ` (${i})`}</option>)}
                </select>
              </div>
            ))}
          </div>
          <motion.div key={`${b1}-${b2}-${b3}-${b4}`} initial={{ opacity: 0.7, y: 4 }} animate={{ opacity: 1, y: 0 }} transition={{ duration: 0.25 }}>
            <div className="bg-gradient-to-br from-yellow-500 to-yellow-700 rounded-2xl p-6 mb-4 text-center shadow-lg">
              <p className="text-xs font-semibold uppercase tracking-widest text-white/70 mb-1">Resistance Value</p>
              <p className="text-4xl font-black text-white tracking-tight" data-testid="result-resistance">{fmtR(resistance)}</p>
              <p className="text-white/70 text-sm mt-1">Tolerance: {tolerance}</p>
            </div>
            <div className="grid grid-cols-2 gap-3">
              <div className="bg-accent/60 border border-border rounded-xl p-4 text-center">
                <p className="text-xs text-muted-foreground font-medium mb-1">Minimum Resistance</p>
                <p className="text-base font-extrabold text-foreground">{fmtR(minR)}</p>
              </div>
              <div className="bg-accent/60 border border-border rounded-xl p-4 text-center">
                <p className="text-xs text-muted-foreground font-medium mb-1">Maximum Resistance</p>
                <p className="text-base font-extrabold text-foreground">{fmtR(maxR)}</p>
              </div>
            </div>
          </motion.div>
        </section>
        <ShareButton />

        <section className="mb-8 space-y-6">
          <h2 className="text-2xl font-bold text-foreground">How to Decode Resistor Color Codes for Free</h2>
          <div className="bg-accent/60 border border-border rounded-2xl p-5 font-mono text-sm text-foreground space-y-1">
            <p>Resistance = (Band1  x  10 + Band2)  x  Multiplier</p>
            <p>Tolerance range = Resistance  x  (1 - tolerance%)</p>
            <p className="text-xs text-muted-foreground mt-2">Series: R_total = R1 + R2 + R3...</p>
            <p className="text-xs text-muted-foreground">Parallel: 1/R_total = 1/R1 + 1/R2 + 1/R3...</p>
            <p className="text-xs text-muted-foreground">LED resistor: R = (Vsupply - Vled) / Iled</p>
          </div>

          <h2 className="text-2xl font-bold text-foreground">How to Read 4-Band Resistor Color Codes</h2>
          <div className="overflow-x-auto">
            <table className="w-full text-sm border border-border rounded-xl overflow-hidden">
              <thead className="bg-muted/60">
                <tr>
                  {["Color", "Digit Value", "Multiplier", "Tolerance"].map(h => <th key={h} className="text-left py-3 px-4 font-semibold text-foreground">{h}</th>)}
                </tr>
              </thead>
              <tbody className="divide-y divide-border">
                {COLOR_TABLE.map(([color, digit, mult, tol]) => (
                  <tr key={color} className="hover:bg-muted/30">
                    <td className="py-2.5 px-4 font-bold text-foreground">
                      <span className="inline-block w-4 h-4 rounded mr-2 align-middle border border-black/20" style={{ backgroundColor: COLOR_HEX[color] || "#ccc" }} />
                      {color}
                    </td>
                    <td className="py-2.5 px-4 text-muted-foreground">{digit}</td>
                    <td className="py-2.5 px-4 text-yellow-600 dark:text-yellow-400 font-medium">{mult}</td>
                    <td className="py-2.5 px-4 text-muted-foreground">{tol}</td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        </section>

        <section className="mb-8 space-y-6">
          <h2 className="text-2xl font-bold text-foreground">Free Electronics Resistor Tool for Students and Engineers</h2>
          <p className="text-muted-foreground leading-relaxed">Use this free electrical tool on mobile or desktop to check values quickly, compare scenarios, and support wiring or electronics work.</p>
        </section>

        <section className="mb-8">
          <h3 className="text-xl font-bold text-foreground mb-4">Frequently Asked Questions</h3>
          <div className="space-y-3">{FAQS.map(f => <FAQItem key={f.q} q={f.q} a={f.a} />)}</div>
        </section>
        <AdPlaceholder size="rectangle" className="mx-auto mb-8" />
        <RelatedTools exclude="/resistor-calculator" headingLevel="h3" />
      </main>
    </>
  );
}


